(function(){
  var questions = [{"type":"mcq","html":"A pass mark should include a score of exactly 50 as well as scores above 50. Which comparison operator means <span class=\"green-keyword\">greater than or equal to</span>?","correct":">=","options":[">",">=","==","!="],"right":">= includes 50 and anything greater.","wrong":"> means greater than only, so it would not include exactly 50."},{"type":"text","html":"Write a full if block that checks whether <span class=\"green-keyword\">score</span> is at least <span class=\"green-keyword\">50</span>, then prints a short pass message on the indented line underneath. Use this structure:<br><span class=\"code-func\">if</span> condition:<br>&nbsp;&nbsp;&nbsp;&nbsp;<span class=\"code-func\">print</span>(message)","correct":"if score >= 50:\n    print('Passed')","pattern":"^\\s*if\\s+score\\s*>=\\s*50\\s*:\\s*\\n\\s+print\\s*\\(\\s*[\"'][^\"']+[\"']\\s*\\)\\s*$","right":"The if line has a colon, and the print line is indented underneath.","wrong":"Use two lines: if score >= 50: then an indented print(...) line.","multiline":true},{"type":"mcq","html":"The operator <span class=\"green-keyword\">!=</span> means <span class=\"green-keyword\">not equal to</span>. Read this full if block:<br><span class=\"code-func\">if</span> <span class=\"green-keyword\">lives</span> != 0:<br>&nbsp;&nbsp;&nbsp;&nbsp;<span class=\"code-func\">print</span>(<span class=\"code-string\">\"Alive\"</span>)<br>What does the condition check?","correct":"Checks lives is not zero","options":["Checks lives is not zero","Checks lives equals zero","Assigns lives to zero"],"right":"!= means not equal to.","wrong":"!= checks that the two values are different."},{"type":"text","html":"Two conditions both need to be true before the if block should run. Type the Python logical operator that means <span class=\"green-keyword\">both conditions must be True</span>.","correct":"and","pattern":"^\\s*and\\s*$","right":"and requires both sides to be True.","wrong":"Use the logical operator that means both conditions are required."},{"type":"mcq","html":"This full if block checks whether age is inside a range. Because it uses <span class=\"code-func\">and</span>, both comparisons must be true:<br><span class=\"code-func\">if</span> <span class=\"green-keyword\">age</span> >= 11 <span class=\"code-func\">and</span> <span class=\"green-keyword\">age</span> <= 18:<br>&nbsp;&nbsp;&nbsp;&nbsp;<span class=\"code-func\">print</span>(<span class=\"code-string\">\"Allowed\"</span>)<br>Which statement describes it?","correct":"Both comparisons must be True","options":["Both comparisons must be True","Only one comparison must be True","The condition is flipped"],"right":"and requires both conditions.","wrong":"and means the left comparison and the right comparison must both be True."},{"type":"text","html":"Write a full if block that checks whether <span class=\"green-keyword\">role</span> is exactly the string <span class=\"green-keyword\">player</span>, then prints a short message on the indented line underneath.","correct":"if role == \"player\":\n    print(\"Player\")","pattern":"^\\s*if\\s+role\\s*==\\s*[\"']player[\"']\\s*:\\s*\\n\\s+print\\s*\\(\\s*[\"'][^\"']+[\"']\\s*\\)\\s*$","right":"Use == for equality, quotes for the string, and indent the print line.","wrong":"Use two lines: if role == \"player\": then an indented print(...) line.","multiline":true},{"type":"mcq","html":"A Boolean variable stores either <span class=\"green-keyword\">True</span> or <span class=\"green-keyword\">False</span>. This full if block uses the Boolean variable directly:<br><span class=\"code-func\">if</span> <span class=\"green-keyword\">game_over</span>:<br>&nbsp;&nbsp;&nbsp;&nbsp;<span class=\"code-func\">print</span>(<span class=\"code-string\">\"Game over\"</span>)<br>When will the indented line run?","correct":"Runs when game_over is True","options":["Runs when game_over is True","Runs when game_over is False","Always runs"],"right":"The condition runs when it is True.","wrong":"An if block runs only when its condition is True."},{"type":"text","html":"Sometimes you need to flip a condition, so True becomes False and False becomes True. Type the Python logical operator that does this.","correct":"not","pattern":"^\\s*not\\s*$","right":"not flips True to False or False to True.","wrong":"Use the logical operator that flips a condition."},{"type":"mcq","html":"The operator <span class=\"green-keyword\">&gt;</span> means strictly greater than. It does not include the value itself. Read this full if block:<br><span class=\"code-func\">if</span> <span class=\"green-keyword\">temperature</span> &gt; 30:<br>&nbsp;&nbsp;&nbsp;&nbsp;<span class=\"code-func\">print</span>(<span class=\"code-string\">\"Hot\"</span>)<br>What happens when temperature is exactly 30?","correct":"30 does not pass this check","options":["30 does not pass this check","30 passes this check","Only 30 passes this check"],"right":"> means strictly greater than.","wrong":"30 is equal to 30, not greater than 30."},{"type":"text","html":"Write a full if block that checks whether <span class=\"green-keyword\">attempts</span> is exactly equal to <span class=\"green-keyword\">3</span>, then prints a short message on the indented line underneath.","correct":"if attempts == 3:\n    print('Three attempts')","pattern":"^\\s*if\\s+attempts\\s*==\\s*3\\s*:\\s*\\n\\s+print\\s*\\(\\s*[\"'][^\"']+[\"']\\s*\\)\\s*$","right":"Use == for equality and indent the print line under the if line.","wrong":"Use two lines: if attempts == 3: then an indented print(...) line.","multiline":true}];
  var helpSlides = [{"title":"Comparison operators","body":"<p>Comparisons ask a true-or-false question. Common operators are <code>></code> greater than, <code><</code> less than, <code>>=</code> greater than or equal to, <code><=</code> less than or equal to, <code>==</code> equal to, and <code>!=</code> not equal to.</p><p class=\"mt-2\">Use <code>==</code> to compare values. A single <code>=</code> is for storing a value in a variable.</p>"},{"title":"if statement structure","body":"<p>An if statement starts with <code>if</code>, then a condition, then a colon. The code that runs must go on the next line and be indented.</p><pre class=\"bg-gray-100 p-2 rounded mt-2\"><code>if score >= 50:\n    print(\"Passed\")</code></pre>"},{"title":"Text and equality","body":"<p>When comparing text, put the text value in quote marks. The variable name is not in quotes, but the string value is.</p><pre class=\"bg-gray-100 p-2 rounded mt-2\"><code>if role == \"player\":\n    print(\"Player\")</code></pre>"},{"title":"Logical operators","body":"<p><code>and</code> means both conditions must be True. <code>or</code> means at least one condition must be True. <code>not</code> flips a condition.</p><pre class=\"bg-gray-100 p-2 rounded mt-2\"><code>if not game_over:\n    print(\"Continue\")</code></pre>"}];
  var idx=0, score=0, answered=false, results=[];
  var modal=document.getElementById('selection2-dna-help-modal');
  var helpTitle=document.getElementById('selection2-dna-help-title');
  var helpBody=document.getElementById('selection2-dna-help-body');
  var helpPager=document.getElementById('selection2-dna-help-pager');
  var helpPrev=document.getElementById('selection2-dna-help-prev');
  var helpNext=document.getElementById('selection2-dna-help-next');
  var helpIdx=0;
  function renderSlide(){
    var slide=helpSlides[helpIdx];
    helpTitle.textContent=slide.title;
    helpBody.innerHTML=slide.body;
    helpPager.textContent=(helpIdx+1)+' / '+helpSlides.length;
    helpPrev.disabled=helpIdx===0;
    helpNext.textContent=helpIdx===helpSlides.length-1?'Close':'Next';
  }
  document.getElementById('selection2-dna-help-btn').onclick=function(){ helpIdx=0; renderSlide(); modal.classList.remove('hidden'); };
  document.getElementById('selection2-dna-help-close').onclick=function(){ modal.classList.add('hidden'); };
  helpPrev.onclick=function(){ if(helpIdx>0){ helpIdx--; renderSlide(); } };
  helpNext.onclick=function(){ if(helpIdx<helpSlides.length-1){ helpIdx++; renderSlide(); } else { modal.classList.add('hidden'); } };
  modal.addEventListener('click', function(e){ if(e.target===modal) modal.classList.add('hidden'); });

  var qEl=document.getElementById('selection2-dna-q');
  var optEl=document.getElementById('selection2-dna-opts');
  var ansWrap=document.getElementById('selection2-dna-answer-wrap');
  var fbEl=document.getElementById('selection2-dna-fb');
  var progEl=document.getElementById('selection2-dna-prog');
  var scoreEl=document.getElementById('selection2-dna-score');

  function normalize(s){ return String(s).trim().replace(/[??]/g,'"').replace(/[??]/g,"'"); }
  function esc(str){ return String(str).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;'); }
  function checkText(q, raw){
    var val=normalize(raw);
    if(q.pattern) return new RegExp(q.pattern,'i').test(val);
    if(q.answers) return q.answers.some(function(a){ return normalize(a).toLowerCase()===val.toLowerCase(); });
    return normalize(q.correct).toLowerCase()===val.toLowerCase();
  }
  function show(){
    if(idx>=questions.length){ finish(); return; }
    var q=questions[idx]; answered=false;
    progEl.textContent='Question '+(idx+1)+' of '+questions.length;
    scoreEl.textContent='Score: '+score;
    qEl.innerHTML='<span class="ex-code">'+q.html+'</span>';
    optEl.innerHTML=''; ansWrap.innerHTML=''; fbEl.textContent=''; fbEl.className='ex-feedback';
    if(q.type==='text') renderText(q); else renderMcq(q);
  }
  function renderMcq(q){
    q.options.forEach(function(o){
      var btn=document.createElement('button'); btn.className='ex-opt'; btn.textContent=o;
      btn.onclick=function(){
        if(answered) return; answered=true;
        optEl.querySelectorAll('.ex-opt').forEach(function(b){ b.disabled=true; if(b.textContent===q.correct) b.classList.add('correct'); });
        var ok=o===q.correct;
        results.push({q:q, wasCorrect:ok, chosen:o});
        if(ok){ btn.classList.add('correct'); score++; scoreEl.textContent='Score: '+score; fbEl.className='ex-feedback ok'; fbEl.textContent='Correct.'; setTimeout(function(){ idx++; show(); }, 900); }
        else { btn.classList.add('wrong'); fbEl.className='ex-feedback err'; fbEl.textContent='Incorrect. The answer is: '+q.correct; setTimeout(function(){ idx++; show(); }, 1800); }
      };
      optEl.appendChild(btn);
    });
  }
  function renderText(q){
    ansWrap.innerHTML=q.multiline?'<textarea id="selection2-dna-answer" class="ex-textarea" rows="3" spellcheck="false" placeholder="if condition:\\n    print(\"Message\")"></textarea><button id="selection2-dna-check" class="ex-btn" style="margin-top:8px">Check</button>':'<input id="selection2-dna-answer" class="ex-input" type="text" autocomplete="off" spellcheck="false" placeholder="Type your answer here"/><button id="selection2-dna-check" class="ex-btn" style="margin-top:8px">Check</button>';
    var input=document.getElementById('selection2-dna-answer');
    var btn=document.getElementById('selection2-dna-check');
    function submit(){
      if(answered) return;
      var val=input.value;
      if(!val.trim()){ fbEl.className='ex-feedback hint'; fbEl.textContent='Type your answer first.'; return; }
      answered=true;
      input.disabled=true; btn.disabled=true;
      var ok=checkText(q,val);
      results.push({q:q, wasCorrect:ok, chosen:val});
      if(ok){ input.classList.add('correct'); score++; scoreEl.textContent='Score: '+score; fbEl.className='ex-feedback ok'; fbEl.textContent='Correct.'; setTimeout(function(){ idx++; show(); }, 900); }
      else { input.classList.add('wrong'); fbEl.className='ex-feedback err'; fbEl.textContent='Incorrect. Expected: '+q.correct; setTimeout(function(){ idx++; show(); }, 2200); }
    }
    btn.onclick=submit;
    input.onkeydown=function(e){ if(e.key==='Enter' && !q.multiline) submit(); if(e.key==='Enter' && e.ctrlKey) submit(); };
    input.focus();
  }
  function finish(){
    var pct=Math.round(score/questions.length*100);
    qEl.innerHTML=''; optEl.innerHTML=''; ansWrap.innerHTML=''; fbEl.textContent=''; progEl.textContent='Complete'; scoreEl.textContent='';
    var resultsEl=document.getElementById('selection2-dna-results'); resultsEl.classList.remove('hidden');
    var msg=pct===100?'Full marks. You are ready to build on last lesson.':pct>=70?'Good work overall. Review anything you missed below.':'A few areas to revisit before moving on.';
    var html='<div class="ex-box"><p style="font-family:sans-serif;font-size:0.95rem;font-weight:600;color:#cdd6f4;margin-bottom:4px">'+score+'/'+questions.length+' - '+pct+'%</p><p style="font-family:sans-serif;font-size:0.85rem;color:#a6adc8;margin-bottom:16px">'+msg+'</p>';
    results.forEach(function(r){
      html+='<div style="display:flex;align-items:flex-start;gap:10px;margin-bottom:8px;padding:8px 10px;background:'+(r.wasCorrect?'#1a2f20':'#2a1a1a')+';border:1px solid '+(r.wasCorrect?'#2d4a35':'#4a2a2a')+';border-radius:6px">';
      html+='<span style="color:'+(r.wasCorrect?'#a6e3a1':'#f38ba8')+';font-size:1rem;flex-shrink:0;margin-top:1px">'+(r.wasCorrect?'&#10003;':'&#10007;')+'</span>';
      html+='<div><div class="ex-code" style="font-size:0.82rem;margin-bottom:3px">'+r.q.html+'</div>';
      html+='<p style="font-family:sans-serif;font-size:0.78rem;color:#a6adc8;margin:0 0 3px 0">Your answer: <strong style="color:'+(r.wasCorrect?'#a6e3a1':'#f38ba8')+'">'+esc(r.chosen)+'</strong> - expected: <strong style="color:#a6e3a1">'+esc(r.q.correct)+'</strong></p>';
      html+='<p style="font-family:sans-serif;font-size:0.8rem;color:#bac2de;margin:0">'+(r.wasCorrect?r.q.right:(r.q.wrong||r.q.right))+'</p></div></div>';
    });
    html+='</div>'; resultsEl.innerHTML=html;
    window.__markStepComplete && window.__markStepComplete();
  }
  show();
})();

