.ex-btn{display:inline-block;background:#2563eb;color:white;border:0;border-radius:6px;padding:8px 14px;font-family:sans-serif;font-size:0.85rem;font-weight:600;cursor:pointer}
.ex-btn:hover:not([disabled]){background:#1d4ed8}
.ex-btn[disabled]{opacity:0.55;cursor:default}

