quizQuestions.sampleAnswer:
score = 40
if score >= 50:
    print("Pass")
else:
    print("Try again")

lives = 0
if lives != 0:
    print("Alive")
else:
    print("Game over")

game_over = False
if not game_over:
    print("Continue")
else:
    print("Stop")
